const CONFIG = require('../Main_file');
// emailService.js — HRMS Email Notification Service
// Provider: Brevo (Sendinblue) via HTTP API (not SMTP — Render blocks SMTP ports)
// Add to .env:
//   BREVO_API_KEY=your-brevo-api-key   (from Brevo → Settings → SMTP & API → API keys)
//   EMAIL_FROM=${process.env.EMAIL_FROM}  (must be verified sender in Brevo)
//   EMAIL_FROM_NAME=HRMS
//   EMAIL_ENABLED=true

const db = require('./db');

const FROM_NAME  = process.env.EMAIL_FROM_NAME || CONFIG.senderName || 'HRMS';
const FROM_EMAIL = process.env.EMAIL_FROM      || '${process.env.EMAIL_FROM}';
const ENABLED    = process.env.EMAIL_ENABLED === 'true';

// ── Base HTML Template ────────────────────────────────────────────────────────
function baseTemplate(title, bodyHtml, previewText = '') {
  return `<!DOCTYPE html>
<html lang="en" xmlns="http://www.w3.org/1999/xhtml">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="x-apple-disable-message-reformatting">
<title>${title}</title>
<!--[if mso]>
<noscript><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml></noscript>
<![endif]-->
</head>
<body style="margin:0;padding:0;background:#f4f7f0;font-family:Arial,Helvetica,sans-serif;">
<div style="display:none;max-height:0;overflow:hidden;font-size:1px;color:#f4f7f0;">${previewText}&nbsp;&zwnj;&nbsp;</div>

<!-- WRAPPER -->
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f4f7f0;">
<tr><td align="center" style="padding:24px 16px;">

  <!-- CONTAINER -->
  <table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width:600px;width:100%;">

    <!-- HEADER -->
    <tr>
      <td align="center" style="background:#1B5E20;border-radius:12px 12px 0 0;padding:28px 32px;">
        <table cellpadding="0" cellspacing="0" border="0" align="center">
          <tr>
            <td align="center">
              <img src="data:image/png;base64," alt="HRMS Logo" width="80" height="80" style="border-radius:12px;display:block;margin-bottom:10px;">
            </td>
          </tr>
          <tr>
            <td align="center">
              <div style="color:#ffffff;font-size:30px;font-weight:800;letter-spacing:-0.5px;font-family:Arial,sans-serif;line-height:1.2;">
                Krishi<span style="color:#A5D6A7;">HR</span>
              </div>
              <div style="color:#C8E6C9;font-size:11px;margin-top:6px;letter-spacing:2px;text-transform:uppercase;font-family:Arial,sans-serif;">
                ${CONFIG.companyFullName}
              </div>
            </td>
          </tr>
        </table>
      </td>
    </tr>

    <!-- BODY -->
    <tr>
      <td style="background:#ffffff;padding:32px;border-left:1px solid #e0e0e0;border-right:1px solid #e0e0e0;">
        ${bodyHtml}
      </td>
    </tr>

    <!-- FOOTER -->
    <tr>
      <td style="background:#F1F8E9;border-radius:0 0 12px 12px;padding:16px 32px;text-align:center;border:1px solid #e0e0e0;border-top:none;">
        <p style="font-size:11px;color:#999;margin:4px 0;">This is an automated email from HRMS. Please do not reply.</p>
        <p style="font-size:11px;color:#999;margin:4px 0;">
          ${CONFIG.companyFullName} Pvt. Ltd. &nbsp;|&nbsp;
          <a href="https://${CONFIG.websiteUrl}" style="color:#2E7D32;text-decoration:none;">${CONFIG.websiteUrl}</a>
        </p>
      </td>
    </tr>

  </table>
  <!-- /CONTAINER -->

</td></tr>
</table>
<!-- /WRAPPER -->

</body>
</html>`;
}

// ── Send helper ───────────────────────────────────────────────────────────────
async function send({ to, toName, subject, html, preview }) {
  if (!ENABLED) {
    console.log(`[Email DISABLED] Would send to ${to}: ${subject}`);
    return;
  }
  const apiKey = process.env.BREVO_API_KEY;
  if (!apiKey) {
    console.warn('[Email] BREVO_API_KEY not set — skipping email');
    return;
  }
  try {
    const body = JSON.stringify({
      sender:  { name: FROM_NAME, email: FROM_EMAIL },
      to:      [{ email: to, name: toName || to }],
      subject,
      htmlContent: baseTemplate(subject, html, preview || subject),
    });

    const res = await fetch('https://api.brevo.com/v3/smtp/email', {
      method:  'POST',
      headers: {
        'accept':       'application/json',
        'api-key':      apiKey,
        'content-type': 'application/json',
      },
      body,
    });

    const data = await res.json();
    if (res.ok) {
      console.log(`[Email] Sent to ${to}: ${subject}`);
    } else {
      console.error(`[Email] Failed to ${to}:`, JSON.stringify(data));
    }
  } catch (err) {
    console.error(`[Email] Failed to ${to}:`, err.message);
  }
}

// ── Get employee email helper ─────────────────────────────────────────────────
async function getEmp(id) {
  const r = await db.query(
    `SELECT e.id, e.first_name, e.last_name, e.email, e.employee_code,
            d.name AS department, des.title AS designation
     FROM employees e
     LEFT JOIN departments d ON e.department_id=d.id
     LEFT JOIN designations des ON e.designation_id=des.id
     WHERE e.id=$1 AND e.is_active=true`, [id]
  );
  return r.rows[0] || null;
}

async function getHREmails() {
  const r = await db.query(
    `SELECT email, first_name, last_name FROM employees WHERE role='hr' AND is_active=true`
  );
  return r.rows;
}

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
function fmtDate(d) {
  if (!d) return '—';
  const dt = new Date(d);
  return `${String(dt.getDate()).padStart(2,'0')} ${MONTHS[dt.getMonth()]} ${dt.getFullYear()}`;
}

