            <tr><td style="padding:8px 16px;color:#666;font-weight:500;font-size:13px;width:45%;border-bottom:1px solid #E8F5E9;">Status</td><td style="padding:8px 16px;color:#1B5E20;font-weight:700;font-size:13px;text-align:right;border-bottom:1px solid #E8F5E9;"><span class="badge badge-red">Rejected</span></td></tr>
