// ── Daily cron helpers (called from server.js cron) ───────────────────────────

// Send birthday emails today
async function sendDailyBirthdayEmails() {
  try {
    const today = new Intl.DateTimeFormat('en-CA', { timeZone: CONFIG.timezone || 'Asia/Kolkata',
      month:'2-digit', day:'2-digit' }).format(new Date());
    const r = await db.query(
      `SELECT id FROM employees
       WHERE is_active=true AND date_of_birth IS NOT NULL
         AND TO_CHAR(date_of_birth,'MM-DD') = $1`, [today]
    );
    for (const emp of r.rows) {
      await notifyBirthday(emp.id);
    }
    if (r.rows.length) console.log(`[Email] Sent birthday emails to ${r.rows.length} employee(s)`);
  } catch(e) { console.error('[Email] sendDailyBirthdayEmails:', e.message); }
}

// Send anniversary emails today
async function sendDailyAnniversaryEmails() {
  try {
    const today = new Intl.DateTimeFormat('en-CA', { timeZone: CONFIG.timezone || 'Asia/Kolkata',
      month:'2-digit', day:'2-digit' }).format(new Date());
    const currentYear = new Date().getFullYear();
    const r = await db.query(
      `SELECT id, EXTRACT(YEAR FROM joining_date)::int AS join_year
       FROM employees
       WHERE is_active=true AND joining_date IS NOT NULL
         AND TO_CHAR(joining_date,'MM-DD') = $1
         AND EXTRACT(YEAR FROM joining_date)::int < $2`,
      [today, currentYear]
    );
    for (const emp of r.rows) {
      const years = currentYear - emp.join_year;
      await notifyAnniversary(emp.id, years);
    }
    if (r.rows.length) console.log(`[Email] Sent anniversary emails to ${r.rows.length} employee(s)`);
  } catch(e) { console.error('[Email] sendDailyAnniversaryEmails:', e.message); }
}

// ── OD REQUEST — notify manager / approvers ───────────────────────────────────
async function notifyODApplied(employeeId, date, reason, location) {
  try {
    const emp = await db.query(
      `SELECT e.first_name, e.last_name, e.employee_code,
              d.name AS department,
              m.first_name AS mgr_fname, m.last_name AS mgr_lname, m.email AS mgr_email
       FROM employees e
       LEFT JOIN departments d ON e.department_id=d.id
       LEFT JOIN employees m ON e.reporting_manager_id=m.id
       WHERE e.id=$1`, [employeeId]
    );
    if (!emp.rows.length) return;
    const e = emp.rows[0];

    // KC718 (COO) OD → notify MD (super_admin / KC01) only
    // All other employees → notify their reporting manager only (fallback: HR)
    const recipients = [];
    if (e.employee_code === CONFIG.cooEmployeeCode) {
      const md = await db.query(
        `SELECT email, first_name, last_name FROM employees
         WHERE role = 'super_admin' AND is_active=true AND email IS NOT NULL LIMIT 1`
      );
      for (const m of md.rows) recipients.push({ email: m.email, name: `${m.first_name} ${m.last_name}` });
    } else if (e.mgr_email) {
      recipients.push({ email: e.mgr_email, name: `${e.mgr_fname} ${e.mgr_lname}` });
    } else {
      const hr = await db.query(
        `SELECT email, first_name, last_name FROM employees
         WHERE role = 'hr' AND is_active=true AND email IS NOT NULL LIMIT 3`
      );
      for (const h of hr.rows) recipients.push({ email: h.email, name: `${h.first_name} ${h.last_name}` });
    }

    for (const r of recipients) {
      await send({
        to:      r.email,
        toName:  r.name,
        subject: `🚗 OD Request — ${e.first_name} ${e.last_name}`,
        preview: `${e.first_name} has requested Outdoor Duty for ${date}. Reason: ${reason}`,
        html:    buildODHtml(e, date, reason, location)
      });
    }
  } catch(err) { console.error('[Email] notifyODApplied:', err.message); }
}

