// ── SEPARATION INITIATED — notify employee ────────────────────────────────────
async function notifySeparationInitiated(separationId) {
  try {
    const r = await db.query(
      `SELECT s.*, e.first_name, e.last_name, e.email, e.employee_code,
              e.joining_date, d.name AS department
       FROM separations s
       JOIN employees e ON s.employee_id=e.id
       LEFT JOIN departments d ON e.department_id=d.id
       WHERE s.id=$1`, [separationId]
    );
    if (!r.rows.length || !r.rows[0].email) return;
    const s = r.rows[0];
    await send({
      to: s.email, toName: `${s.first_name} ${s.last_name}`,
      subject: `📢 Separation Notice Initiated`,
      preview: `Your separation process has been initiated. Last Working Day: ${fmtDate(s.last_working_date)}`,
      html: `
        <div style="font-size:22px;font-weight:800;color:#1B5E20;margin:0 0 8px;font-family:Arial,sans-serif;">📢 Separation Initiated</div>
        <div style="font-size:14px;color:#64748B;margin:0 0 20px;">Your separation from ${CONFIG.companyFullName} has been initiated.</div>
        <table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;border-left:4px solid #EF4444;border-radius:0 8px 8px 0;margin:16px 0;border-collapse:collapse;">
          <tr><td style="padding:8px 16px;color:#64748B;font-weight:500;font-size:13px;width:45%;border-bottom:1px solid #F1F5F9;">Employee</td><td style="padding:8px 16px;color:#1E293B;font-weight:700;font-size:13px;text-align:right;border-bottom:1px solid #F1F5F9;">${s.first_name} ${s.last_name} (${s.employee_code})</td></tr>
          <tr><td style="padding:8px 16px;color:#64748B;font-weight:500;font-size:13px;width:45%;border-bottom:1px solid #F1F5F9;">Type</td><td style="padding:8px 16px;color:#1E293B;font-weight:700;font-size:13px;text-align:right;border-bottom:1px solid #F1F5F9;">${s.type||'Resignation'}</td></tr>
          <tr><td style="padding:8px 16px;color:#64748B;font-weight:500;font-size:13px;width:45%;border-bottom:1px solid #F1F5F9;">Last Working Day</td><td style="padding:8px 16px;color:#EF4444;font-weight:700;font-size:14px;text-align:right;border-bottom:1px solid #F1F5F9;">${fmtDate(s.last_working_date)}</td></tr>
          <tr><td style="padding:8px 16px;color:#64748B;font-weight:500;font-size:13px;width:45%;">Status</td><td style="padding:8px 16px;text-align:right;"><span style="background:#FEE2E2;color:#DC2626;padding:3px 10px;border-radius:999px;font-size:12px;font-weight:700;">In Progress</span></td></tr>
        </table>
        <p style="font-size:13px;color:#64748B;margin-top:14px;font-family:Arial,sans-serif;">Please ensure all handovers are completed before your last working day. Contact HR for any queries.</p>`
    });
  } catch(err) { console.error('[Email] notifySeparationInitiated:', err.message); }
}


